import json

from typing import Dict, List, Tuple

MARKOV_CHAIN_DEFAULT_ORDER = 1

class MarkovChain:
    def __init__(self, order: int = MARKOV_CHAIN_DEFAULT_ORDER):
        self.order = order
        self.chain: Dict[Tuple[str, ...], str] = {}

    def train(self, text: str) -> None:
        words = text.split()
        for i in range(len(words) - self.order):
            key = tuple(words[i:i + self.order])
            value = words[i + self.order]
            if key not in self.chain:
                self.chain[key] = []
            self.chain[key].append(value)

    def generate(self, length: int, seed: str | None = None, random_seed: int | None = None) -> str:
        words = [seed or ''] if seed else ['a' * self.order]
        for _ in range(length):
            key = tuple(words[-self.order:])
            if key not in self.chain:
                break
            choices = self.chain[key]
            value = choices[random.randint(0, len(choices) - 1)] if random_seed else choices[0]
            words.append(value)
        return ''.join(words)

    def to_dict(self) -> Dict[str, str]:
        return {str(key): value for key, value in self.chain.items()}

    @classmethod
    def from_dict(cls, data: Dict[str, str]) -> 'MarkovChain':
        chain = cls()
        for key, value in data.items():
            chain.add_key_value(key, value)
        return chain
